+        let allowed = operations_info().as_array().is_some_and(|ops| {
+            ops.iter()
+                .any(|o| o.get("id").and_then(serde_json::Value::as_str) == Some(operation))
+        });
+
+        Ok(json!({
+            "allowed": allowed,
+            "reason": if allowed { "Operation supported" } else { "Unknown operation" },
+        }))
+    }
