+}
+
+/// Next page cursor.
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct NextPage {
+    pub page: Option<i64>,
+    pub starting_after: Option<String>,
+}
+
+/// `Intercom` API error response.
+#[derive(Debug, Clone, Deserialize)]
+pub struct ApiErrorResponse {
+    #[serde(rename = "type")]
