+//! FCP `PandaDoc` Connector - Main entrypoint
+//!
+//! A `PandaDoc` document automation connector implementing the Flywheel Connector Protocol.
+//! Provides access to documents, templates, and sending.
+
+#![forbid(unsafe_code)]
+#![allow(dead_code)]
+#![allow(
+    clippy::cast_possible_truncation,
+    clippy::cast_precision_loss,
+    clippy::cast_sign_loss,
+    clippy::derivable_impls,
+    clippy::future_not_send,
+    clippy::manual_unwrap_or_default,
+    clippy::match_same_arms,
+    clippy::option_if_let_else,
+    clippy::or_fun_call,
+    clippy::redundant_closure_for_method_calls,
+    clippy::struct_field_names,
+    clippy::too_many_lines,
+    clippy::trivially_copy_pass_by_ref,
+    clippy::unreadable_literal,
+    clippy::unused_async
+)]
+
+use std::io::{BufRead, Write};
+
+use anyhow::Result;
+use fcp_async_core::runtime::Builder;
+use tracing_subscriber::{EnvFilter, layer::SubscriberExt, util::SubscriberInitExt};
+
+use fcp_pandadoc::connector::PandaDocConnector;
+
+fn main() -> Result<()> {
+    tracing_subscriber::registry()
+        .with(EnvFilter::try_from_default_env().unwrap_or_else(|_| EnvFilter::new("info")))
+        .with(tracing_subscriber::fmt::layer().with_writer(std::io::stderr))
+        .init();
+
+    tracing::info!("FCP PandaDoc Connector starting");
+    run_fcp_loop()?;
+    Ok(())
+}
+
+fn run_fcp_loop() -> Result<()> {
+    let stdin = std::io::stdin();
+    let mut stdout = std::io::stdout();
+    let mut connector = PandaDocConnector::new();
+
+    let runtime = Builder::new_multi_thread().enable_all().build()?;
+
+    for line in stdin.lock().lines() {
+        let Ok(line) = line else { break };
+        if line.is_empty() {
+            continue;
+        }
+
+        let response = runtime.block_on(async { handle_message(&mut connector, &line).await });
+
+        let response_json = serde_json::to_string(&response)?;
+        writeln!(stdout, "{response_json}")?;
+        stdout.flush()?;
+    }
+
+    Ok(())
+}
+
+async fn handle_message(connector: &mut PandaDocConnector, message: &str) -> serde_json::Value {
+    let request: serde_json::Value = match serde_json::from_str(message) {
+        Ok(v) => v,
+        Err(e) => {
+            return serde_json::json!({
+                "error": {
+                    "code": "FCP-1001",
+                    "message": format!("Invalid JSON: {e}")
+                }
+            });
+        }
+    };
+
+    let method = request.get("method").and_then(serde_json::Value::as_str).unwrap_or("");
+    let id = request.get("id").cloned();
+    let params = request
+        .get("params")
+        .cloned()
+        .unwrap_or_else(|| serde_json::json!({}));
+
+    let result = match method {
+        "configure" => connector.handle_configure(params).await,
+        "handshake" => connector.handle_handshake(params).await,
+        "health" => connector.handle_health().await,
+        "doctor" => connector.handle_doctor().await,
+        "self_check" => connector.handle_self_check().await,
+        "introspect" => connector.handle_introspect().await,
+        "invoke" => connector.handle_invoke(params).await,
+        "simulate" => connector.handle_simulate(params).await,
+        "shutdown" => connector.handle_shutdown(params).await,
+        _ => Err(fcp_core::FcpError::InvalidRequest {
+            code: 1002,
+            message: format!("Unknown method: {method}"),
+        }),
+    };
+
+    match result {
+        Ok(value) => {
+            let mut response = serde_json::json!({
+                "jsonrpc": "2.0",
+                "result": value
+            });
+            if let Some(id) = id {
+                response["id"] = id;
+            }
+            response
+        }
+        Err(e) => {
+            let err_response = e.to_response();
+            let mut response = serde_json::json!({
+                "jsonrpc": "2.0",
+                "error": err_response
+            });
+            if let Some(id) = id {
+                response["id"] = id;
+            }
+            response
+        }
+    }
+}

